const payload = ($json.body && typeof $json.body === 'object') ? $json.body : $json;
const filepath = typeof payload.filepath === 'string' ? payload.filepath.trim() : '';
const filename = typeof payload.filename === 'string' && payload.filename.trim() ? payload.filename.trim() : (filepath ? filepath.split('/').pop() : 'watch-payload.txt');
const content = typeof payload.content === 'string' ? payload.content : '';
const explicitProjectSlug = typeof payload.project_slug === 'string' && payload.project_slug.trim() ? payload.project_slug.trim() : '';
const inferredProjectSlug = (() => {
  if (!filepath) return '';
  const parts = filepath.split('/').filter(Boolean);
  const inboxIndex = parts.findIndex((part) => part === 'inbox');
  if (inboxIndex >= 0 && parts.length - inboxIndex >= 3) return parts[inboxIndex + 1];
  return '';
})();
const projectSlug = explicitProjectSlug || inferredProjectSlug || null;
if (!filepath && !content.trim()) return [{ json: { request_ok: false, ok: false, error: { code: 'INVALID_WATCH_INPUT', message: 'Provide filepath and/or content to crispybrain-auto-ingest-watch' } } }];
return [{ json: { request_ok: true, filepath: filepath || `inline://${filename}`, filename, content, project_slug: projectSlug, modifiedEpoch: payload.modifiedEpoch !== undefined && payload.modifiedEpoch !== null ? Number(payload.modifiedEpoch) : null, source: { kind: 'auto_ingest_watch', label: 'auto_ingest_watch', path: filepath || null }, watch: { inferred_project_slug: inferredProjectSlug || null, explicit_project_slug: explicitProjectSlug || null, request_source: 'crispybrain-auto-ingest-watch' } } }];

const handoff = $('Build Watch Handoff').first().json;
const statusCode = $json.statusCode ?? 0;
const body = $json.body ?? {};
if (statusCode < 200 || statusCode >= 300 || body.ok !== true) {
  return [{ json: { ok: false, error: { code: 'INGEST_HANDOFF_FAILED', message: 'crispybrain-ingest did not accept the auto-ingest handoff', status: statusCode || null, details: body.error ?? body ?? null }, filepath: handoff.filepath, filename: handoff.filename, project_slug: handoff.project_slug, watch: handoff.watch, ingest: body } }];
}
return [{ json: { ok: true, filepath: handoff.filepath, filename: handoff.filename, project_slug: handoff.project_slug, watch: handoff.watch, ingest: body, execution_log: { workflow_chain: ['crispybrain-auto-ingest-watch', 'crispybrain-ingest'], handed_off: true, inserted_count: body.inserted_count ?? 0 } } }];
